 19→type ChatRequestBody = {
 20→  messages: UIMessage[];
 21→  workspaceId: string;
 22→  conversationId?: string;
 23→  onboardingAction?: OnboardingAction;
 24→  discussEntityId?: string;
 25→};
 26→
 27→const onboardingActions = new Set(["finalize_onboarding", "continue_onboarding"]);
 28→
 29→export function createChatRouteHandler(deps: ServerDependencies) {
 30→  return (request: Request) => handleChatRequest(deps, request);
 31→}
 32→
 33→async function handleChatRequest(deps: ServerDependencies, request: Request): Promise<Response> {
 34→  const startedAt = performance.now();
 35→
 36→  let body: ChatRequestBody;
 37→  try {
 38→    body = await request.json() as ChatRequestBody;
 39→  } catch {
 40→    return jsonError("Request body must be valid JSON", 400);
 41→  }
 42→
 43→  if (!body.workspaceId || body.workspaceId.trim().length === 0) {
 44→    return jsonError("workspaceId is required", 400);
 45→  }
 46→  if (!Array.isArray(body.messages) || body.messages.length === 0) {
 47→    return jsonError("messages array is required", 400);
 48→  }
 49→  if (body.onboardingAction && !onboardingActions.has(body.onboardingAction)) {
 50→    return jsonError("onboardingAction must be finalize_onboarding or continue_onboarding", 400);
 51→  }
 52→
 53→  const lastMessage = body.messages[body.messages.length - 1];
 54→  if (lastMessage.role !== "user") {
 55→    return jsonError("last message must be a user message", 400);
 56→  }
 57→
 58→  const userText = extractTextFromUIMessage(lastMessage);
 59→  if (userText.trim().length === 0) {
 60→    return jsonError("user message text is required", 400);
 61→  }
 62→
 63→  const conversationId = body.conversationId ?? randomUUID();
 64→  const messageId = randomUUID();
 65→  const userMessageRecord = new RecordId("message", randomUUID());
 66→
 67→  let workspaceRecord: RecordId<"workspace", string>;
 68→
 69→  try {
 70→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, body.workspaceId);
 71→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
 72→    if (!workspace) {
 73→      throw new HttpError(404, `workspace not found: ${body.workspaceId}`);
 74→    }
 75→
 76→    const discussEntityTables = ["project", "person", "feature", "task", "decision", "question", "observation"] as const;
 77→    const discussesRecord = body.discussEntityId
 78→      ? parseRecordIdString(body.discussEntityId, [...discussEntityTables])
 79→      : undefined;
 80→
 81→    const now = new Date();
 82→    const conversationRecord = new RecordId("conversation", conversationId);
 83→    const existingConversation = await deps.surreal.select<ConversationRow>(conversationRecord);
 84→
 85→    // Persist user message in transaction
 86→    const transaction = await deps.surreal.beginTransaction();
 87→    try {
 88→      if (existingConversation) {
 89→        if (!existingConversation.workspace) {
 90→          throw new HttpError(500, "conversation is missing workspace scope");
 91→        }
 92→        if (existingConversation.workspace.id !== workspaceRecord.id) {
 93→          throw new HttpError(400, "conversation scope does not match workspaceId");
 94→        }
 95→        await transaction.update(conversationRecord).merge({ updatedAt: now });
 96→      } else {
 97→        await transaction.create(conversationRecord).content({
 98→          createdAt: now,
 99→          updatedAt: now,
100→          workspace: workspaceRecord,
101→          title: deriveMessageTitle(userText),
102→          title_source: "message",
103→          ...(workspace.onboarding_complete ? {} : { source: "onboarding" }),
104→          ...(discussesRecord ? { discusses: discussesRecord } : {}),
105→        });
106→      }
107→
108→      await transaction.create(userMessageRecord).content({
109→        conversation: conversationRecord,
110→        role: "user",
111→        text: userText,
112→        createdAt: now,
113→      });
114→
115→      if (!workspace.onboarding_complete) {
116→        await transaction.update(workspaceRecord).merge({
117→          onboarding_turn_count: workspace.onboarding_turn_count + 1,
118→          updated_at: now,
119→        });
120→      }
121→
122→      await transaction.commit();
123→    } catch (error) {
124→      await transaction.cancel();
125→      throw error;
126→    }
127→
128→    // Embed user message (fire-and-forget)
129→    const userMessageEmbedding = await createEmbedding(deps.embeddingModel, deps.config.embeddingDimension, userText);
130→    if (userMessageEmbedding) {
131→      deps.inflight.track(deps.surreal
132→        .query("UPDATE $record MERGE { embedding: $embedding };", {
133→          record: userMessageRecord,
134→          embedding: userMessageEmbedding,
135→        })
136→        .catch(() => undefined));
137→    }
138→
139→    // Compute onboarding state
140→    const onboardingAfter = await transitionOnboardingState({
141→      surreal: deps.surreal,
142→      workspaceRecord,
143→      workspace,
144→      onboardingAction: body.onboardingAction,
145→      now,
146→    });
147→
148→    // Load branch context
149→    const branchChain = await loadBranchChain(deps.surreal, conversationId);
150→    let inheritedEntityIds: RecordId[] | undefined;
151→    if (branchChain.length > 0) {
152→      const inheritedMsgIds = branchChain.map((b) => new RecordId("message", b));
153→      if (inheritedMsgIds.length > 0) {
154→        const [entityRows] = await deps.surreal
155→          .query<[Array<{ out: RecordId }>]>(
156→            "SELECT DISTINCT out FROM extraction_relation WHERE `in` IN $msgIds LIMIT 30;",
157→            { msgIds: inheritedMsgIds },
158→          )
159→          .collect<[Array<{ out: RecordId }>]>();
160→        inheritedEntityIds = entityRows.map((r) => r.out);
161→      }
162→    }
163→
164→    const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
165→      surreal: deps.surreal,
166→      workspaceRecord,
167→    });
168→
169→    // Build chat context and system prompt
170→    const context = await buildChatContext({
171→      surreal: deps.surreal,
172→      conversationRecord,
173→      workspaceRecord,
174→      ...(userMessageEmbedding ? { userMessageEmbedding } : {}),
175→      ...(inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : {}),
176→      ...(existingConversation?.discusses ? { discussesRecord: existingConversation.discusses } : {}),
177→    });
178→
179→    const system = buildSystemPrompt(context, {
180→      isOnboarding: onboardingAfter !== "complete",
181→      onboardingState: onboardingAfter,
182→    });
183→
184→    // Convert UIMessages to model messages
185→    const modelMessages = await convertToModelMessages(body.messages);
186→
187→    const tools = createChatAgentTools({
188→      surreal: deps.surreal,
189→      pmAgentModel: deps.pmAgentModel,
190→      analyticsAgentModel: deps.analyticsAgentModel,
191→      analyticsSurreal: deps.analyticsSurreal,
192→      embeddingModel: deps.embeddingModel,
193→      embeddingDimension: deps.config.embeddingDimension,
194→      extractionModelId: deps.config.extractionModelId,
195→      extractionModel: deps.extractionModel,
196→      extractionStoreThreshold: deps.config.extractionStoreThreshold,
197→    });
198→
199→    // Stream the response
200→    const result = streamText({
201→      model: deps.chatAgentModel,
202→      system,
203→      messages: modelMessages,
204→      tools,
205→      experimental_context: {
206→        actor: "chat_agent",
207→        workspaceRecord,
208→        conversationRecord,
209→        currentMessageRecord: userMessageRecord,
210→        latestUserText: userText,
211→        ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
212→      },
213→      stopWhen: stepCountIs(5),
214→    });
215→
216→    logInfo("chat.route.streaming", "Streaming chat response", {
217→      conversationId,
218→      messageId,
219→      workspaceId: body.workspaceId,
220→      durationMs: elapsedMs(startedAt),
221→    });
222→
223→    return result.toUIMessageStreamResponse({
224→      sendReasoning: true,
225→      onFinish: async ({ responseMessage }) => {
226→        const rawText = responseMessage.parts
227→          .filter((p): p is Extract<typeof p, { type: "text" }> => p.type === "text")
228→          .map((p) => p.text)
229→          .join("\n");
230→        const assistantText = rawText.trim().length > 0
231→          ? rawText.trim()
232→          : "I could not generate a response for that request.";
233→
234→        // Extract subagent traces from tool parts
235→        const subagentTraces: SubagentTrace[] = [];
236→        for (const part of responseMessage.parts) {
237→          if (part.type === "tool-invoke_pm_agent" && "state" in part && part.state === "output-available" && "output" in part) {
238→            const output = part.output as Record<string, unknown> | undefined;
239→            if (output?.trace) {
240→              subagentTraces.push(output.trace as SubagentTrace);
241→            }
242→          }
243→        }
244→
245→        // Persist assistant message
246→        const assistantMessageRecord = new RecordId("message", messageId);
247→        await deps.surreal.create(assistantMessageRecord).content({
248→          conversation: conversationRecord,
249→          role: "assistant",
250→          text: assistantText,
251→          createdAt: now,
252→          ...(subagentTraces.length > 0 ? { subagent_traces: subagentTraces } : {}),
253→        });
254→
255→        await deps.surreal.update(conversationRecord).merge({ updatedAt: now });
256→
257→        // Post-response hooks
258→        await refreshConversationTouchedBy(deps.surreal, conversationRecord);
259→        await maybeUpgradeConversationTitle(deps.surreal, conversationRecord);
260→
261→        // Fire-and-forget: embeddings
262→        deps.inflight.track(persistEmbeddings({
263→          surreal: deps.surreal,
264→          embeddingModel: deps.embeddingModel,
265→          embeddingDimension: deps.config.embeddingDimension,
266→          assistantMessageRecord,
267→          assistantText,
268→          entities: [],
269→        }).catch(() => undefined));
270→
271→        logInfo("chat.route.completed", "Chat response completed", {
272→          conversationId,
273→          messageId,
274→          workspaceId: body.workspaceId,
275→          durationMs: elapsedMs(startedAt),
276→        });
277→      },
278→      messageMetadata: ({ part }) => {
279→        if (part.type === "finish") {
280→          return { onboardingState: onboardingAfter, conversationId };
281→        }
282→        return { onboardingState: onboardingAfter, conversationId };
283→      },
284→    });
285→  } catch (error) {
286→    if (error instanceof HttpError) {
287→      logWarn("chat.route.http_error", "Chat route failed with client-facing error", {
288→        statusCode: error.status,
289→      });
290→      return jsonError(error.message, error.status);
291→    }
292→
293→    logError("chat.route.failed", "Chat route failed", error, {
294→      conversationId,
295→      messageId,
296→      durationMs: elapsedMs(startedAt),
297→    });
298→    return jsonError("chat processing failed", 500);
299→  }
300→}
301→
302→function extractTextFromUIMessage(message: UIMessage): string {
303→  for (const part of message.parts) {
304→    if (part.type === "text") {
305→      return part.text;
306→    }
307→  }
308→  return "";
309→}
