 30→/**
 31→ * Walk branched_from edges from a conversation up to the root.
 32→ * Returns an ordered array (root-first) of branch links.
 33→ */
 34→export async function loadBranchChain(
 35→  surreal: Surreal,
 36→  conversationId: string,
 37→): Promise<BranchLink[]> {
 38→  const chain: BranchLink[] = [];
 39→  let current = conversationId;
 40→
 41→  for (let depth = 0; depth < 10; depth++) {
 42→    const conversationRecord = new RecordId("conversation", current);
 43→    const [rows] = await surreal
 44→      .query<[Array<{
 45→        out: RecordId<"conversation", string>;
 46→        branch_point_message: RecordId<"message", string>;
 47→      }>]>(
 48→        "SELECT out, branch_point_message FROM branched_from WHERE `in` = $conversation LIMIT 1;",
 49→        { conversation: conversationRecord },
 50→      )
 51→      .collect<[Array<{
 52→        out: RecordId<"conversation", string>;
 53→        branch_point_message: RecordId<"message", string>;
 54→      }>]>();
 55→
 56→    if (rows.length === 0) break;
 57→
 58→    const edge = rows[0];
 59→    const branchPointMsg = await surreal.select<{ createdAt: Date | string }>(edge.branch_point_message);
 60→    if (!branchPointMsg) {
 61→      throw new Error(`branch point message not found: ${edge.branch_point_message.id as string}`);
 62→    }
 63→
 64→    chain.unshift({
 65→      conversationId: current,
 66→      parentConversationId: edge.out.id as string,
 67→      branchPointMessageId: edge.branch_point_message.id as string,
 68→      branchPointCreatedAt: branchPointMsg.createdAt instanceof Date
 69→        ? branchPointMsg.createdAt
 70→        : new Date(branchPointMsg.createdAt),
 71→    });
 72→
 73→    current = edge.out.id as string;
 74→  }
 75→
 76→  return chain;
 77→}
