 79→/**
 80→ * Load all messages for a conversation including inherited messages from ancestor branches.
 81→ * Inherited messages are marked with `inherited: true`.
 82→ */
 83→export async function loadMessagesWithInheritance(
 84→  surreal: Surreal,
 85→  conversationId: string,
 86→  limit: number,
 87→): Promise<InheritableMessage[]> {
 88→  const chain = await loadBranchChain(surreal, conversationId);
 89→
 90→  if (chain.length === 0) {
 91→    const messages = await queryConversationMessages(surreal, conversationId, limit);
 92→    return messages.map((m) => toInheritable(m, false));
 93→  }
 94→
 95→  const allMessages: InheritableMessage[] = [];
 96→
 97→  // Root conversation messages up to first branch point
 98→  const rootConvId = chain[0].parentConversationId;
 99→  const rootMessages = await queryMessagesUpToBranchPoint(
100→    surreal,
101→    rootConvId,
102→    chain[0].branchPointCreatedAt,
103→  );
104→  allMessages.push(...rootMessages.map((m) => toInheritable(m, true)));
105→
106→  // Intermediate ancestor messages between branch points
107→  for (let i = 0; i < chain.length - 1; i++) {
108→    const intermediateMessages = await queryMessagesUpToBranchPoint(
109→      surreal,
110→      chain[i].conversationId,
111→      chain[i + 1].branchPointCreatedAt,
112→    );
113→    allMessages.push(...intermediateMessages.map((m) => toInheritable(m, true)));
114→  }
115→
116→  // Current conversation's own messages
117→  const ownMessages = await queryConversationMessages(surreal, conversationId, limit);
118→  allMessages.push(...ownMessages.map((m) => toInheritable(m, false)));
119→
120→  return allMessages;
121→}
122→
123→function toInheritable(row: MessageRow, inherited: boolean): InheritableMessage {
124→  return {
125→    id: row.id.id as string,
126→    role: row.role,
127→    text: row.text,
128→    createdAt: row.createdAt,
129→    ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
130→    ...(row.subagent_traces && row.subagent_traces.length > 0 ? { subagent_traces: row.subagent_traces } : {}),
131→    inherited,
132→  };
133→}
