135→async function queryConversationMessages(
136→  surreal: Surreal,
137→  conversationId: string,
138→  limit: number,
139→): Promise<MessageRow[]> {
140→  const conversationRecord = new RecordId("conversation", conversationId);
141→  const [rows] = await surreal
142→    .query<[MessageRow[]]>(
143→      "SELECT id, role, text, createdAt, suggestions, subagent_traces FROM message WHERE conversation = $conversation ORDER BY createdAt ASC LIMIT $limit;",
144→      { conversation: conversationRecord, limit },
145→    )
146→    .collect<[MessageRow[]]>();
147→  return rows;
148→}
