150→/**
151→ * Load messages from a conversation up to and including the branch point message
152→ * and its assistant response (the next message after the branch point).
153→ */
154→async function queryMessagesUpToBranchPoint(
155→  surreal: Surreal,
156→  conversationId: string,
157→  branchPointCreatedAt: Date,
158→): Promise<MessageRow[]> {
159→  const conversationRecord = new RecordId("conversation", conversationId);
160→
161→  // Find the assistant response following the branch point (if any)
162→  const [nextRows] = await surreal
163→    .query<[MessageRow[]]>(
164→      "SELECT id, role, text, createdAt, suggestions, subagent_traces FROM message WHERE conversation = $conversation AND createdAt > $branchPointAt ORDER BY createdAt ASC LIMIT 1;",
165→      { conversation: conversationRecord, branchPointAt: branchPointCreatedAt },
166→    )
167→    .collect<[MessageRow[]]>();
168→
169→  const cutoffAt = nextRows.length > 0 && nextRows[0].role === "assistant"
170→    ? (nextRows[0].createdAt instanceof Date ? nextRows[0].createdAt : new Date(nextRows[0].createdAt as string))
171→    : branchPointCreatedAt;
172→
173→  const [rows] = await surreal
174→    .query<[MessageRow[]]>(
175→      "SELECT id, role, text, createdAt, suggestions, subagent_traces FROM message WHERE conversation = $conversation AND createdAt <= $cutoff ORDER BY createdAt ASC;",
176→      { conversation: conversationRecord, cutoff: cutoffAt },
177→    )
178→    .collect<[MessageRow[]]>();
179→
180→  return rows;
181→}
