 1→import { tool } from "ai";
 2→import { z } from "zod";
 3→import { runPmAgent } from "../../agents/pm/agent";
 4→import { logError } from "../../http/observability";
 5→import { requireToolContext } from "./helpers";
 6→import type { ChatAgentToolDeps } from "./types";
 7→
 8→export function createInvokePmAgentTool(deps: ChatAgentToolDeps) {
 9→  return tool({
10→    description:
11→      "Invoke the PM subagent — the single authority on tasks, features, and project status.",
12→    inputSchema: z.object({
13→      intent: z
14→        .enum(["plan_work", "check_status", "organize", "track_dependencies"])
15→        .describe(
16→          "plan_work: user discusses goals, features, or work to be done. check_status: user asks about progress, blockers, or project status. organize: user wants to restructure or re-prioritize. track_dependencies: user asks about blocked items or dependency chains.",
17→        ),
18→      context: z.string().min(1).describe("The relevant parts of the user's message for the PM agent. Forward the user's words — do NOT pre-classify what is a project, feature, or task. The PM agent decides entity classification."),
19→    }),
20→    execute: async (input, options) => {
21→      const context = requireToolContext(options);
22→
23→      try {
24→        return await runPmAgent({
25→          deps,
26→          context,
27→          intent: input.intent,
28→          conversationContext: input.context,
29→        });
30→      } catch (error) {
31→        logError("tool.invoke_pm_agent.failed", "PM agent invocation failed", error, {
32→          intent: input.intent,
33→          workspace: context.workspaceRecord.toString(),
34→          conversation: context.conversationRecord.toString(),
35→        });
36→        throw error;
37→      }
38→    },
39→  });
40→}
